mapper.select:
SELECT id, listing_id, neighbourhood_cleansed, room_type, price, number_of_reviews, review_scores_rating
FROM price_review_relation


        AND (
            neighbourhood_cleansed LIKE CONCAT('%', #{param.keyword}, '%')
            OR room_type LIKE CONCAT('%', #{param.keyword}, '%')
        )


        AND neighbourhood_cleansed LIKE CONCAT('%', #{param.neighbourhoodCleansed}, '%')


        AND room_type LIKE CONCAT('%', #{param.roomType}, '%')


        AND listing_id = #{param.listingId}


        AND price = #{param.price}


        AND number_of_reviews = #{param.numberOfReviews}


        AND review_scores_rating = #{param.reviewScoresRating}


ORDER BY id DESC
